/// <summary>
/// Controller class for ETGScaleTicketReport
/// </summary>
class ETGScaleTicketReportController extends SrsReportRunController
{
}

Method.Source:
public static void main(Args _args)
{
    ETGScaleTicketReportController controller = new ETGScaleTicketReportController();
    controller.parmArgs(_args);
    controller.parmReportName(ssrsReportStr(ETGScaleTicketReport, ReportMain));
    controller.parmShowDialog(false);
    controller.startOperation();
}

public void prePromptModifyContract()
{
    ETGScaleTicketTable          scaleTable = this.parmArgs().record();
    ETGScaleTicketReportContract contract   = this.parmReportContract().parmRdpContract();
    contract.parmScaleTicketNum(scaleTable.ScaleTicketNumber);
}
